const emailsOriginaux = $('Limite - Emails').all();
const threads = $input.all();

// Déduplique les threads par id
const threadsMap = {};
threads.forEach(t => {
  if (!threadsMap[t.json.id]) {
    threadsMap[t.json.id] = t.json;
  }
});

let resultats = [];

emailsOriginaux.forEach((emailItem, index) => {
  let dossiersPersos = [];

  // Cherche le thread correspondant par id plutôt que par index
  const threadId = emailItem.json.threadId || emailItem.json.id;
  const threadActuel = threadsMap[threadId] || threads[index]?.json;

  if (threadActuel && threadActuel.messages) {
    threadActuel.messages.forEach(msg => {
      if (msg.labels) {
        msg.labels.forEach(label => {
          if (label.id.startsWith('Label_') && !dossiersPersos.some(d => d.id === label.id)) {
            dossiersPersos.push({ id: label.id, name: label.name });
          }
        });
      }
    });
  }

  resultats.push({
    json: {
      ...emailItem.json,
      deja_classe: dossiersPersos.length > 0,
      dossiers_trouves: dossiersPersos
    },
    pairedItem: { item: index }
  });
});

return resultats;

const allItems = $input.all();

// On ignore uniquement les labels système inutiles pour le classement
const systemLabelsToIgnore = [
  'chat', 'draft', 'trash', 'spam', 'starred', 'unread', 
  'category_', 'circle', 'star'
];

const labelsPropres = allItems
  .map(item => item.json)
  .filter(label => {
    const n = label.name.toLowerCase();

    // 1. On vire le "bruit" système
    if (systemLabelsToIgnore.some(sys => n.includes(sys))) return false;

    // 2. On ne garde que tes dossiers (type "user")
    // On peut aussi garder INBOX ou SENT si tu veux, mais pour classer, on ne garde que les dossiers créés par toi.
    return label.type === 'user';
  })
  .map(label => `- [${label.id}] : ${label.name}`);

return [{
  json: {
    liste_dossiers_texte: labelsPropres.join('\n'),
    stats: {
      labels_envoyes_ia: labelsPropres.length
    }
  }
}];

const message = $json.choices[0].message;
const text = (message.content || '').trim();

if (!text) {
  return { json: { error: true, skip: true, emailId: $json.gmail_id, raw: 'content vide' } };
}

const cleaned = text
  .replace(/^```json\n?/, '')
  .replace(/```$/, '')
  .trim();

try {
  const parsed = JSON.parse(cleaned);

  const promptTokens = $json.usage?.prompt_tokens || 0;
  const completionTokens = $json.usage?.completion_tokens || 0;
  const cachedTokens = $json.usage?.prompt_cache_hit_tokens || 0;
  const uncachedTokens = promptTokens - cachedTokens;

  const coutInput = (uncachedTokens / 1_000_000) * 0.14;
  const coutInputCache = (cachedTokens / 1_000_000) * 0.014;
  const coutOutput = (completionTokens / 1_000_000) * 0.28;
  const coutTotal = coutInput + coutInputCache + coutOutput;

  return {
    json: {
      ...parsed,
      id: $json.gmail_id,
      threadId: $json.gmail_threadId,
      internalDate: $json.internalDate,
      skip: false,
      prompt_tokens: promptTokens,
      completion_tokens: completionTokens,
      cached_tokens: cachedTokens,
      cache_ratio: promptTokens > 0 ? Math.round((cachedTokens / promptTokens) * 100) : 0,
      cout_usd: Math.round(coutTotal * 1_000_000) / 1_000_000,
      cout_eur: Math.round(coutTotal * 0.92 * 1_000_000) / 1_000_000
    }
  };
} catch(e) {
  const repaired = cleaned
    .replace(/\\(?!")/g, '\\\\')
    .replace(/[\u201C\u201D]/g, '"');
  try {
    return { json: { ...JSON.parse(repaired), id: $json.gmail_id, threadId: $json.gmail_threadId, skip: false } };
  } catch(e2) {
    return { json: { error: true, skip: true, emailId: $json.gmail_id, raw: cleaned } };
  }
}

const emails = $input.all();
const nbEmails = emails.length;

// Seuil : on chauffe le cache seulement si > 5 emails
const seuilChauffe = 4;

return emails.map((item, index) => ({
  json: {
    ...item.json,
    nb_emails: nbEmails,
    chauffe_necessaire: nbEmails > seuilChauffe,
    index: index
  }
}));

const usage = $json.usage;
const cachedTokens = usage.prompt_cache_hit_tokens || 0;
const promptTokens = usage.prompt_tokens || 1;
const cacheRatio = cachedTokens / promptTokens;

const cacheChaud = cacheRatio > 0.7;
const tentatives = $('Code JS - Chauffe cache').item.json.tentatives || 0;

return {
  json: {
    cache_chaud: cacheChaud || tentatives >= 3,
    cache_ratio: Math.round(cacheRatio * 100),
    cached_tokens: cachedTokens,
    prompt_tokens: promptTokens,
    tentatives: tentatives + 1
  }
};
